function detectOpening() {
  const sequence = game.history.map(m => normalizeSan(m.san)); let best = { name: 'Unclassified Opening', line: [] };
  for (const opening of OPENINGS) { let matched = 0; while (matched < sequence.length && matched < opening.line.length && sequence[matched] === opening.line[matched]) matched++; if (matched > best.line.length && matched === Math.min(sequence.length, opening.line.length)) best = opening; }
  return best;
}
function isBookAt(index) {
  if (index > 15) return false; const sequence = game.history.slice(0, index + 1).map(m => normalizeSan(m.san)); return OPENINGS.some(o => sequence.every((move, i) => o.line[i] === move));
}
