function renderOpening() {
  const opening = detectOpening(); $('openingName').textContent = opening.name; $('openingChip').textContent = opening.name; $('openingDescription').textContent = opening.name === 'Unclassified Opening' ? 'Posisi telah keluar dari opening book lokal.' : `Jalur dikenal hingga ${Math.min(game.history.length, opening.line.length)} ply.`;
  const matching = OPENINGS.filter(o => game.history.map(m => normalizeSan(m.san)).every((move, i) => o.line[i] === move)).slice(0, 5);
  $('openingLines').innerHTML = matching.length ? matching.map(o => `<div class="opening-line"><strong>${escapeHtml(o.name)}</strong><span>${escapeHtml(o.line.join(' '))}</span></div>`).join('') : '<div class="empty-card">Tidak ada lanjutan book lokal.</div>';
}

