    const restored = createGame(data.config, data.initialFen); Object.assign(restored, data); restored.chess = new Chess(data.initialFen); for (const r of data.history) restored.chess.move(parseUci(uciFromRecord(r))); game = restored; resetTransientState(); enterGameView();
